  <React.StrictMode>
    <GoogleOAuthProvider clientId="819593240477-h2eir7oido3gqe18pustup7shkempgme.apps.googleusercontent.com">
      <App />
    </GoogleOAuthProvider>
  </React.StrictMode>
);
